  ('fire-eq-tech-moex-01600', 'fire-eq-tech', 'fire-eq-tech-moex-106-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '五層樓的建築物，每層設有特別安全梯，樓梯採正壓且加壓壓力為35 Pa，每層特別安全梯之前室採正壓且 加壓壓力為25 Pa，居室則未設煙控設計，居室避難到特別安全梯，需經過設有煙控之前室，且空間均為密 閉構造，唯一開口為安全門，流動面積為0.01 m2，試問每一排煙室設加壓煙控時，應送的風量為多少？', '["1.55 m3/s", "0.155 m3/s", "0.0155 m3/s", "1.55 × 10-3 m3/s"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:21+00:00", "source_pdf_sha1": "1d6d766264ab", "answer_pdf_sha1": "81aee902f39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "106060", "c": "502", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "106", "exam_name": "106年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
